def _req_id(headers):
    "Extract provider request id header when available."
    if headers is None: return ""
    for k in ("x-request-id", "request-id", "anthropic-request-id", "x-goog-request-id"):
        v = headers.get(k)
        if v: return str(v)
    return ""

